# 自定义函数 + 条件筛选的列表推导式
# f(v)：偶数平方，奇数加1；列表推导式中过滤掉 v<=0 的元素

def f(v):
    if v%2==0:
        v=v**2
    else:
        v=v+1
    return v

# 只对 v>0 的元素调用 f()，-1 被过滤
print([f(v)for v in [2,3,4,-1]if v>0])

# 使用字典统计字符串中每个字符的出现次数
# 利用 get() 方法为首次出现的字符初始化计数为 0

text='Python is a powerful programming language'
char_count={}
for ch in text:
    # get(ch,0)：键不存在时返回 0，实现首次计数
    char_count[ch]=char_count.get(ch,0)+1

# 输出每个字符及其出现次数
for i,v in char_count.items():
    print(i,':',v)

# 字典实现角色权限映射：根据用户角色返回对应的权限列表
# 使用 get() 为未知角色返回空列表，避免 KeyError

#配置多条件映射
#根据用户角色分配用户权限
role_permissions={
    'admin':['read','write','delete','create','manage'],
    'user':['read','write'],
    'viewer':['read']
}

def get_user_permissions(role):
    """根据角色名获取权限列表，未知角色返回空列表"""
    return role_permissions.get(role,[])

# 遍历测试角色
for role in ['admin', 'user', 'viewer', 'unknown']:
    print(f"{role.title()} Permissions", get_user_permissions(role))

